32	static unique_ptr<Expression> AddCastExpressionInternal(unique_ptr<Expression> expr, const LogicalType &target_type,
33	                                                        BoundCastInfo bound_cast, bool try_cast) {
34		if (ExpressionBinder::GetExpressionReturnType(*expr) == target_type) {
35			return expr;
36		}
37		auto &expr_type = expr->return_type;
38		if (target_type.id() == LogicalTypeId::LIST && expr_type.id() == LogicalTypeId::LIST) {
39			auto &target_list = ListType::GetChildType(target_type);
40			auto &expr_list = ListType::GetChildType(expr_type);
41			if (target_list.id() == LogicalTypeId::ANY || expr_list == target_list) {
42				return expr;
43			}
44		}
45		auto result = make_uniq<BoundCastExpression>(std::move(expr), target_type, std::move(bound_cast), try_cast);
46		result->SetQueryLocation(result->child->GetQueryLocation());
47		return std::move(result);
48	}
