50	static unique_ptr<Expression> AddCastToTypeInternal(unique_ptr<Expression> expr, const LogicalType &target_type,
51	                                                    CastFunctionSet &cast_functions, GetCastFunctionInput &get_input,
52	                                                    bool try_cast) {
53		D_ASSERT(expr);
54		if (expr->GetExpressionClass() == ExpressionClass::BOUND_PARAMETER) {
55			auto &parameter = expr->Cast<BoundParameterExpression>();
56			if (!target_type.IsValid()) {
57				// invalidate the parameter
58				parameter.parameter_data->return_type = LogicalType::INVALID;
59				parameter.return_type = target_type;
60				return expr;
61			}
62			if (parameter.parameter_data->return_type.id() == LogicalTypeId::INVALID) {
63				// we don't know the type of this parameter
64				parameter.return_type = target_type;
65				return expr;
66			}
67			if (parameter.parameter_data->return_type.id() == LogicalTypeId::UNKNOWN) {
68				// prepared statement parameter cast - but there is no type, convert the type
69				parameter.parameter_data->return_type = target_type;
70				parameter.return_type = target_type;
71				return expr;
72			}
73			// prepared statement parameter already has a type
74			if (parameter.parameter_data->return_type == target_type) {
75				// this type! we are done
76				parameter.return_type = parameter.parameter_data->return_type;
77				return expr;
78			}
79			// invalidate the type
80			parameter.parameter_data->return_type = LogicalType::INVALID;
81			parameter.return_type = target_type;
82			return expr;
83		} else if (expr->GetExpressionClass() == ExpressionClass::BOUND_DEFAULT) {
84			D_ASSERT(target_type.IsValid());
85			auto &def = expr->Cast<BoundDefaultExpression>();
86			def.return_type = target_type;
87		}
88		if (!target_type.IsValid()) {
89			return expr;
90		}
91	
92		auto cast_function = cast_functions.GetCastFunction(expr->return_type, target_type, get_input);
93		return AddCastExpressionInternal(std::move(expr), target_type, std::move(cast_function), try_cast);
94	}
