120	bool BoundCastExpression::CastIsInvertible(const LogicalType &source_type, const LogicalType &target_type) {
121		D_ASSERT(source_type.IsValid() && target_type.IsValid());
122		if (source_type.id() == LogicalTypeId::BOOLEAN || target_type.id() == LogicalTypeId::BOOLEAN) {
123			return false;
124		}
125		if (source_type.id() == LogicalTypeId::FLOAT || target_type.id() == LogicalTypeId::FLOAT) {
126			return false;
127		}
128		if (source_type.id() == LogicalTypeId::DOUBLE || target_type.id() == LogicalTypeId::DOUBLE) {
129			return false;
130		}
131		if (source_type.id() == LogicalTypeId::VARIANT || target_type.id() == LogicalTypeId::VARIANT) {
132			return false;
133		}
134		if (source_type.id() == LogicalTypeId::DECIMAL || target_type.id() == LogicalTypeId::DECIMAL) {
135			uint8_t source_width, target_width;
136			uint8_t source_scale, target_scale;
137			// cast to or from decimal
138			// cast is only invertible if the cast is strictly widening
139			if (!source_type.GetDecimalProperties(source_width, source_scale)) {
140				return false;
141			}
142			if (!target_type.GetDecimalProperties(target_width, target_scale)) {
143				return false;
144			}
145			if (target_scale < source_scale) {
146				return false;
147			}
148			return true;
149		}
150		switch (source_type.id()) {
151		case LogicalTypeId::TIMESTAMP:
152		case LogicalTypeId::TIMESTAMP_TZ:
153		case LogicalTypeId::TIMESTAMP_SEC:
154		case LogicalTypeId::TIMESTAMP_MS:
155		case LogicalTypeId::TIMESTAMP_NS:
156			switch (target_type.id()) {
157				// see types.hpp to see timestamp ranking
158			case LogicalTypeId::TIMESTAMP:
159				return source_type.id() <= LogicalTypeId::TIMESTAMP;
160			case LogicalTypeId::TIMESTAMP_SEC:
161				return source_type.id() <= LogicalTypeId::TIMESTAMP_SEC;
162			case LogicalTypeId::TIMESTAMP_MS:
163				return source_type.id() <= LogicalTypeId::TIMESTAMP_MS;
164			case LogicalTypeId::TIMESTAMP_NS:
165				return source_type.id() <= LogicalTypeId::TIMESTAMP_NS;
166			case LogicalTypeId::DATE:
167			case LogicalTypeId::TIME:
168			case LogicalTypeId::TIME_TZ:
169				return false;
170			case LogicalTypeId::TIMESTAMP_TZ:
171				return source_type.id() == LogicalTypeId::TIMESTAMP_TZ;
172			default:
173				break;
174			}
175			break;
176		case LogicalTypeId::VARCHAR:
177		case LogicalTypeId::BIT:
178		case LogicalTypeId::TIME_TZ:
179			return false;
180		default:
181			break;
182		}
183		if (target_type.id() == LogicalTypeId::VARCHAR) {
184			switch (source_type.id()) {
185			case LogicalTypeId::DATE:
186			case LogicalTypeId::TIME:
187			case LogicalTypeId::TIME_NS:
188			case LogicalTypeId::TIMESTAMP:
189			case LogicalTypeId::TIMESTAMP_NS:
190			case LogicalTypeId::TIMESTAMP_MS:
191			case LogicalTypeId::TIMESTAMP_SEC:
192			case LogicalTypeId::TIME_TZ:
193			case LogicalTypeId::TIMESTAMP_TZ:
194				return true;
195			default:
196				return false;
197			}
198		}
199		if (source_type.IsSigned() && target_type.IsUnsigned()) {
200			return false;
201		}
202		return true;
203	}
