229	bool BoundCastExpression::CanThrow() const {
230		const auto child_type = child->return_type;
231		if (return_type.id() != child_type.id() &&
232		    LogicalType::ForceMaxLogicalType(return_type, child_type) == child_type.id()) {
233			return true;
234		}
235		// Casting VARCHAR to JSON involves parsing and validation that can throw on malformed input
236		if (return_type.IsJSONType() && !child_type.IsJSONType()) {
237			return true;
238		}
239		bool changes_type = false;
240		ExpressionIterator::EnumerateChildren(*this, [&](const Expression &child) { changes_type |= child.CanThrow(); });
241		return changes_type;
242	}
