200	unique_ptr<ExpressionState> ExpressionExecutor::InitializeState(const Expression &expr,
201	                                                                ExpressionExecutorState &state) {
202		switch (expr.GetExpressionClass()) {
203		case ExpressionClass::BOUND_REF:
204			return InitializeState(expr.Cast<BoundReferenceExpression>(), state);
205		case ExpressionClass::BOUND_BETWEEN:
206			return InitializeState(expr.Cast<BoundBetweenExpression>(), state);
207		case ExpressionClass::BOUND_CASE:
208			return InitializeState(expr.Cast<BoundCaseExpression>(), state);
209		case ExpressionClass::BOUND_CAST:
210			return InitializeState(expr.Cast<BoundCastExpression>(), state);
211		case ExpressionClass::BOUND_COMPARISON:
212			return InitializeState(expr.Cast<BoundComparisonExpression>(), state);
213		case ExpressionClass::BOUND_CONJUNCTION:
214			return InitializeState(expr.Cast<BoundConjunctionExpression>(), state);
215		case ExpressionClass::BOUND_CONSTANT:
216			return InitializeState(expr.Cast<BoundConstantExpression>(), state);
217		case ExpressionClass::BOUND_FUNCTION:
218			return InitializeState(expr.Cast<BoundFunctionExpression>(), state);
219		case ExpressionClass::BOUND_OPERATOR:
220			return InitializeState(expr.Cast<BoundOperatorExpression>(), state);
221		case ExpressionClass::BOUND_PARAMETER:
222			return InitializeState(expr.Cast<BoundParameterExpression>(), state);
223		default:
224			throw InternalException("Attempting to initialize state of expression of unknown type!");
225		}
226	}
227	
228	void ExpressionExecutor::Execute(const Expression &expr, ExpressionState *state, const SelectionVector *sel,
229	                                 idx_t count, Vector &result) {
230	#ifdef DEBUG
231		// The result vector must be used for the first time, or must be reset.
232		// Otherwise, the validity mask can contain previous (now incorrect) data.
233		if (result.GetVectorType() == VectorType::FLAT_VECTOR) {
234			// We do not initialize vector caches for these expressions.
235			if (expr.GetExpressionClass() != ExpressionClass::BOUND_REF &&
236			    expr.GetExpressionClass() != ExpressionClass::BOUND_CONSTANT &&
237			    expr.GetExpressionClass() != ExpressionClass::BOUND_PARAMETER) {
238				D_ASSERT(FlatVector::ValidityMutable(result).CheckAllValid(count));
239			}
240		}
241	#endif
242	
243		if (count == 0) {
244			return;
245		}
246		if (result.GetType().id() != expr.return_type.id()) {
247			throw InternalException(
248			    "ExpressionExecutor::Execute called with a result vector of type %s that does not match expression type %s",
249			    result.GetType(), expr.return_type);
250		}
251		switch (expr.GetExpressionClass()) {
252		case ExpressionClass::BOUND_BETWEEN:
253			Execute(expr.Cast<BoundBetweenExpression>(), state, sel, count, result);
254			break;
255		case ExpressionClass::BOUND_REF:
256			Execute(expr.Cast<BoundReferenceExpression>(), state, sel, count, result);
257			break;
258		case ExpressionClass::BOUND_CASE:
259			Execute(expr.Cast<BoundCaseExpression>(), state, sel, count, result);
260			break;
261		case ExpressionClass::BOUND_CAST:
262			Execute(expr.Cast<BoundCastExpression>(), state, sel, count, result);
263			break;
264		case ExpressionClass::BOUND_COMPARISON:
265			Execute(expr.Cast<BoundComparisonExpression>(), state, sel, count, result);
266			break;
267		case ExpressionClass::BOUND_CONJUNCTION:
268			Execute(expr.Cast<BoundConjunctionExpression>(), state, sel, count, result);
269			break;
270		case ExpressionClass::BOUND_CONSTANT:
271			Execute(expr.Cast<BoundConstantExpression>(), state, sel, count, result);
272			break;
273		case ExpressionClass::BOUND_FUNCTION:
274			Execute(expr.Cast<BoundFunctionExpression>(), state, sel, count, result);
275			break;
276		case ExpressionClass::BOUND_OPERATOR:
277			Execute(expr.Cast<BoundOperatorExpression>(), state, sel, count, result);
278			break;
279		case ExpressionClass::BOUND_PARAMETER:
280			Execute(expr.Cast<BoundParameterExpression>(), state, sel, count, result);
281			break;
282		default:
283			throw InternalException("Attempting to execute expression of unknown type!");
284		}
285		Verify(expr, result, count);
286	}
287	
288	idx_t ExpressionExecutor::Select(const Expression &expr, ExpressionState *state, const SelectionVector *sel,
289	                                 idx_t count, SelectionVector *true_sel, SelectionVector *false_sel) {
290		if (count == 0) {
291			return 0;
292		}
293		D_ASSERT(true_sel || false_sel);
294		D_ASSERT(expr.return_type.id() == LogicalTypeId::BOOLEAN);
295		switch (expr.GetExpressionClass()) {
296	#ifndef DUCKDB_SMALLER_BINARY
297		case ExpressionClass::BOUND_BETWEEN:
298			return Select(expr.Cast<BoundBetweenExpression>(), state, sel, count, true_sel, false_sel);
299	#endif
300		case ExpressionClass::BOUND_COMPARISON:
301			return Select(expr.Cast<BoundComparisonExpression>(), state, sel, count, true_sel, false_sel);
302		case ExpressionClass::BOUND_CONJUNCTION:
303			return Select(expr.Cast<BoundConjunctionExpression>(), state, sel, count, true_sel, false_sel);
304		case ExpressionClass::BOUND_FUNCTION:
305			return Select(expr.Cast<BoundFunctionExpression>(), state, sel, count, true_sel, false_sel);
306		default:
307			return DefaultSelect(expr, state, sel, count, true_sel, false_sel);
308		}
309	}
310	
311	template <bool NO_NULL, bool HAS_TRUE_SEL, bool HAS_FALSE_SEL>
312	static inline idx_t DefaultSelectLoop(const SelectionVector *bsel, const uint8_t *__restrict bdata, ValidityMask &mask,
313	                                      const SelectionVector *sel, idx_t count, SelectionVector *true_sel,
314	                                      SelectionVector *false_sel) {
315		idx_t true_count = 0, false_count = 0;
316		for (idx_t i = 0; i < count; i++) {
317			auto bidx = bsel->get_index(i);
318			auto result_idx = sel->get_index(i);
319			if ((NO_NULL || mask.RowIsValid(bidx)) && bdata[bidx] > 0) {
320				if (HAS_TRUE_SEL) {
321					true_sel->set_index(true_count++, result_idx);
322				}
323			} else {
324				if (HAS_FALSE_SEL) {
325					false_sel->set_index(false_count++, result_idx);
326				}
327			}
328		}
329		if (HAS_TRUE_SEL) {
330			return true_count;
331		} else {
332			return count - false_count;
333		}
334	}
335	
336	template <bool NO_NULL>
337	static inline idx_t DefaultSelectSwitch(UnifiedVectorFormat &idata, const SelectionVector *sel, idx_t count,
338	                                        SelectionVector *true_sel, SelectionVector *false_sel) {
339		if (true_sel && false_sel) {
340			return DefaultSelectLoop<NO_NULL, true, true>(idata.sel, UnifiedVectorFormat::GetData<uint8_t>(idata),
341			                                              idata.validity, sel, count, true_sel, false_sel);
342		} else if (true_sel) {
343			return DefaultSelectLoop<NO_NULL, true, false>(idata.sel, UnifiedVectorFormat::GetData<uint8_t>(idata),
344			                                               idata.validity, sel, count, true_sel, false_sel);
345		} else {
346			D_ASSERT(false_sel);
347			return DefaultSelectLoop<NO_NULL, false, true>(idata.sel, UnifiedVectorFormat::GetData<uint8_t>(idata),
348			                                               idata.validity, sel, count, true_sel, false_sel);
349		}
350	}
351	
352	idx_t ExpressionExecutor::DefaultSelect(const Expression &expr, ExpressionState *state, const SelectionVector *sel,
353	                                        idx_t count, SelectionVector *true_sel, SelectionVector *false_sel) {
354		// generic selection of boolean expression:
355		// resolve the true/false expression first
356		// then use that to generate the selection vector
357		bool intermediate_bools[STANDARD_VECTOR_SIZE];
358		Vector intermediate(LogicalType::BOOLEAN, data_ptr_cast(intermediate_bools), STANDARD_VECTOR_SIZE);
359		Execute(expr, state, sel, count, intermediate);
360	
361		UnifiedVectorFormat idata;
362		intermediate.ToUnifiedFormat(count, idata);
363	
364		if (!sel) {
365			sel = FlatVector::IncrementalSelectionVector();
366		}
367		if (idata.validity.CanHaveNull()) {
368			return DefaultSelectSwitch<false>(idata, sel, count, true_sel, false_sel);
369		} else {
370			return DefaultSelectSwitch<true>(idata, sel, count, true_sel, false_sel);
371		}
372	}
373	
374	vector<unique_ptr<ExpressionExecutorState>> &ExpressionExecutor::GetStates() {
375		return states;
376	}
377	
378	} // namespace duckdb
